<router-link custom v-slot="{ href, navigate, isActive, isExactActive }" :to="props.path"><li class="item" :class="{ 'router-link-active': isActive, 'router-link-exact-active': isExactActive, 'desktop-only': desktopOnly }"><a class="link" :href="href" @click="[() =&gt; navigate($event), closeNavigation]">{{ routeName }}</a></li></router-link>