<div class="sidebar"><a class="menu-toggle" role="button" @click="toggleNavigation" aria-label="Toggle menu"><MaterialIcon class="menu-icon">{{ menuIcon }}</MaterialIcon></a><div class="project-title" :title="currentRouteName">{{ currentRouteName }}</div><div class="project-selector"><a class="backward" role="button" title="Navigate backward" aria-label="Navigate backward" @click="navigateBackward" :disabled="isStartOfRoutes"><MaterialIcon class="menu-icon">chevron_left</MaterialIcon></a><a class="forward" role="button" title="Navigate forward" aria-label="Navigate forward" @click="navigateForward" :disabled="isEndOfRoutes"><MaterialIcon class="menu-icon">chevron_right</MaterialIcon></a></div></div>